        c = uart_getc();
        if(c == -1) break;
        cons_intr(c);  // 传递给控制台层
    }
    spinlock_acquire(&uart_tx.lk);
    uart_start();      // 继续发送缓冲数据
    spinlock_release(&uart_tx.lk);
}
